// The only ensures of `new()` is `ret.wf()`, i.e. `seq@.len() == N`.
// Re-assert it for both candidate results and unfold to the underlying
// seq-length equality, so z3 has the matching `r1.seq@.len()`,
// `r2.seq@.len()`, and `N` terms in scope when it tries to discharge
// the synthetic `det_new_equal(r1, r2)` check.
assert(r1.wf());
assert(r2.wf());
assert(r1.seq@.len() == N);
assert(r2.seq@.len() == N);
assert(r1.seq@.len() == r2.seq@.len());
